  console.log('==================================================\n');

  // 初始化会话历史记录
  let messages: ChatMessage[] = [{ role: 'system', content: systemPrompt }];

  try {
    while (true) {
      // 绘制输入框的上分隔线
      const screenWidth = process.stdout.columns || 80;
      console.log(colors.gray('─'.repeat(screenWidth)));

      // 优雅的用户提示符
      const userInput = await rl.question(`${colors.boldPurple('👤 你 › ')}`);
      const trimmedInput = userInput.trim();

